import{_ as t,o as r,c as o,ai as a}from"./chunks/framework.CaiDwmc7.js";const m=JSON.parse('{"title":"Spectrum Execution","description":"VS Code Spectrum execution states, SpectrumEngine iteration loop, and SpectrumRunner signal handling.","frontmatter":{"title":"Spectrum Execution","description":"VS Code Spectrum execution states, SpectrumEngine iteration loop, and SpectrumRunner signal handling.","outline":[2,3]},"headers":[],"relativePath":"vscode/spectrum.md","filePath":"vscode/spectrum.md","lastUpdated":1772487797000}'),i={name:"vscode/spectrum.md"};function n(c,e,d,s,l,u){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="spectrum-execution-vs-code" tabindex="-1">Spectrum Execution (VS Code) <a class="header-anchor" href="#spectrum-execution-vs-code" aria-label="Permalink to “Spectrum Execution (VS Code)”">​</a></h1><p>The VS Code extension runs Spectrum through the same signal protocol as the CLI.</p><h2 id="execution-states" tabindex="-1">Execution States <a class="header-anchor" href="#execution-states" aria-label="Permalink to “Execution States”">​</a></h2><table tabindex="0"><thead><tr><th>State</th><th>Description</th></tr></thead><tbody><tr><td><code>idle</code></td><td>Waiting to start</td></tr><tr><td><code>running</code></td><td>Claude CLI active, processing stories</td></tr><tr><td><code>paused</code></td><td>Execution paused by user</td></tr><tr><td><code>complete</code></td><td>All stories finished</td></tr><tr><td><code>maxIterations</code></td><td>Iteration limit reached</td></tr><tr><td><code>error</code></td><td>Fatal error, cannot continue</td></tr></tbody></table><h2 id="spectrumengine" tabindex="-1">SpectrumEngine <a class="header-anchor" href="#spectrumengine" aria-label="Permalink to “SpectrumEngine”">​</a></h2><p>Manages the execution loop state machine. On each iteration:</p><ol><li>Check max iterations — exceeded? → <code>maxIterations</code> state</li><li>Select next story via <code>StoriesManager.getNextStory()</code></li><li>Spawn Claude CLI via <code>SpectrumRunner</code></li><li>Stream output, parse tools and signals</li><li>Handle signal: Continue → pause, then next iteration; Complete → check remaining; Error → stop</li><li>Update stories.json on disk</li></ol><h2 id="spectrumrunner" tabindex="-1">SpectrumRunner <a class="header-anchor" href="#spectrumrunner" aria-label="Permalink to “SpectrumRunner”">​</a></h2><p>Per-iteration CLI subprocess manager:</p><ul><li>Spawns <code>claude</code> with <code>--dangerously-skip-permissions --print --output-format stream-json</code></li><li>Streams stdout/stderr through output parser</li><li>Detects signals (<code>&lt;spectrum-continue&gt;</code>, <code>&lt;spectrum-retry&gt;</code>, <code>&lt;spectrum-blocked&gt;</code>, <code>&lt;spectrum-error&gt;</code>, <code>&lt;promise&gt;COMPLETE&lt;/promise&gt;</code>)</li><li>Fires events: <code>recentActivities[]</code>, <code>logs[]</code>, signal detection</li></ul>',10)])])}const h=t(i,[["render",n]]);export{m as __pageData,h as default};
